ANALYZE sqlite_schema;
CREATE TABLE IF NOT EXISTS "Markets" (
    Market TEXT,
    Monday TEXT,
    Tuesday TEXT,
    Wednesday TEXT,
    Thursday TEXT,
    Friday TEXT,
    Saturday TEXT,
    Sunday TEXT,
    Website TEXT,
    auto_id INTEGER PRIMARY KEY AUTOINCREMENT
);
CREATE TABLE IF NOT EXISTS "Restaurants" (
    Letter TEXT,
    Cuisine TEXT,
    Restaurant TEXT,
    Location TEXT,
    Visit_Date TEXT,
    Comments TEXT,
    auto_id INTEGER PRIMARY KEY AUTOINCREMENT
);
CREATE TABLE IF NOT EXISTS "IconColour" (
    TripID INTEGER UNIQUE NOT NULL,
    trip TEXT NOT NULL,
    icon_colour TEXT NOT NULL,
    auto_id INTEGER PRIMARY KEY AUTOINCREMENT
);
CREATE TABLE IF NOT EXISTS "Maps" (
    ID INTEGER NOT NULL,
    name TEXT,
    address TEXT,
    Country TEXT,
    VisitDate TEXT DEFAULT NULL,
    latitude REAL,
    longitude REAL,
    photo TEXT DEFAULT NULL,
    TripID INTEGER,
    hide INTEGER DEFAULT (0),
    auto_id INTEGER PRIMARY KEY AUTOINCREMENT,
    FOREIGN KEY (TripID) REFERENCES IconColour (TripID) ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "Events" (
    Event TEXT NOT NULL,
    Performer TEXT,
    EventDate TEXT NOT NULL,
    EventTime TEXT,
    Location TEXT,
    Comments TEXT,
    Status TEXT CHECK (Status IN ('Confirmed', 'Performance Cancelled')),
    auto_id INTEGER PRIMARY KEY AUTOINCREMENT
);
CREATE TABLE Cooking (name TEXT NOT NULL UNIQUE, url TEXT CHECK (substr(url, 1, 8) = 'https://') NOT NULL, comments TEXT, rank INTEGER CHECK (rank BETWEEN 1 AND 99), auto_id INTEGER PRIMARY KEY AUTOINCREMENT);

